        data: JSON.stringify(data),
        success: () => {
          this.log('Message sent successfully');
          if (onSuccess) onSuccess();
        },
        fail: (error) => {
          this.log('Message send failed', error);
          if (this.enableQueue) {
            this.enqueueMessage(data, onSuccess, onError, callBackOnRetry);
          }
          if (onError) onError(error);
        },
      });
    } else {
      this.log('WebSocket is not open');
      if (this.enableQueue) {
        this.enqueueMessage(data, onSuccess, onError, callBackOnRetry);
      }
      if (onError) onError(new Error('WebSocket is not open'));
    }
  }

  close() {
    this.isManualClose = true;
    this.currentReconnectAttempts = 0;
    this.clearHeartbeat();
    if (this.webSocket) {
      this.webSocket.close();
    }
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
  }

  setHeader(header) {
    this.header = header;
    this.log('Headers set:', this.header);

    // 如有必要，更新headers后重新连接
    if (this.isConnected()) {
      this.close(); // 断开当前连接
      this.connect(); // 重新连接
    }
  }

  isConnected() {
    return this.webSocket && this.webSocket.readyState === 1;
  }
}

